SELECT
    id AS reportId,
    report_type AS reportType,
    period_start AS periodStart,
    period_end AS periodEnd
FROM biz_learning_report
WHERE user_id = #{userId}

    AND report_type = #{reportType}

ORDER BY period_start DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM biz_learning_report
WHERE user_id = #{userId}

    AND report_type = #{reportType}
